// Extraer proyectoId del body para buscar en Supabase
const body = $input.first().json.body;
const proyectoId = body.proyectoId;

if (!proyectoId) {
  throw new Error('Falta proyectoId');
}

return [{ json: { id: proyectoId, body } }];

// Actualizar tarea dentro de las secciones JSONB
const proyecto = $input.first().json;
const body = $('Extraer ID (Tarea)').first().json.body;
const { seccionNombre, tarea } = body;

if (!seccionNombre || !tarea || !tarea.id) {
  throw new Error('Faltan datos: seccionNombre, tarea.id');
}

let secciones = proyecto.secciones;
if (typeof secciones === 'string') secciones = JSON.parse(secciones);

let encontrada = false;

for (const seccion of secciones) {
  if (seccion.nombre === seccionNombre) {
    const idx = seccion.tareas.findIndex(t => t.id === tarea.id);
    if (idx !== -1) {
      // Merge: mantener campos existentes, actualizar los que vienen
      seccion.tareas[idx] = { ...seccion.tareas[idx], ...tarea };
      encontrada = true;
      break;
    }
    // Buscar en subtareas
    for (const t of seccion.tareas) {
      if (t.subtareas) {
        const subIdx = t.subtareas.findIndex(s => s.id === tarea.id);
        if (subIdx !== -1) {
          t.subtareas[subIdx] = { ...t.subtareas[subIdx], ...tarea };
          encontrada = true;
          break;
        }
      }
    }
    if (encontrada) break;
  }
}

if (!encontrada) {
  // Buscar la tarea en CUALQUIER sección (por si cambió de nombre la sección)
  for (const seccion of secciones) {
    const idx = seccion.tareas.findIndex(t => t.id === tarea.id);
    if (idx !== -1) {
      seccion.tareas[idx] = { ...seccion.tareas[idx], ...tarea };
      encontrada = true;
      break;
    }
  }
}

if (!encontrada) {
  throw new Error(`Tarea ${tarea.id} no encontrada en sección ${seccionNombre}`);
}

// Actualizar ultima_actividad
const hoy = new Date().toISOString().split('T')[0];

return [{ json: {
  id: proyecto.id,
  secciones: JSON.stringify(secciones),
  ultima_actividad: hoy
}}];

// Extraer datos para mover tarea
const body = $input.first().json.body;
const { proyectoId, tareaId, seccionOrigen, seccionDestino } = body;

if (!proyectoId || !tareaId || !seccionOrigen || !seccionDestino) {
  throw new Error('Faltan datos: proyectoId, tareaId, seccionOrigen, seccionDestino');
}

return [{ json: { id: proyectoId, body } }];

// Mover tarea de una sección a otra
const proyecto = $input.first().json;
const body = $('Extraer ID (Mover)').first().json.body;
const { tareaId, seccionOrigen, seccionDestino } = body;

let secciones = proyecto.secciones;
if (typeof secciones === 'string') secciones = JSON.parse(secciones);

if (seccionOrigen === seccionDestino) {
  return [{ json: { id: proyecto.id, secciones: JSON.stringify(secciones) } }];
}

const origen = secciones.find(s => s.nombre === seccionOrigen);
const destino = secciones.find(s => s.nombre === seccionDestino);

if (!origen) throw new Error(`Sección origen no encontrada: ${seccionOrigen}`);
if (!destino) throw new Error(`Sección destino no encontrada: ${seccionDestino}`);

const idx = origen.tareas.findIndex(t => t.id === tareaId);
if (idx === -1) throw new Error(`Tarea ${tareaId} no encontrada en ${seccionOrigen}`);

// Extraer de origen y añadir a destino
const [tarea] = origen.tareas.splice(idx, 1);
destino.tareas.push(tarea);

const hoy = new Date().toISOString().split('T')[0];

return [{ json: {
  id: proyecto.id,
  secciones: JSON.stringify(secciones),
  ultima_actividad: hoy
}}];

// Preparar actualización de anotaciones
const body = $input.first().json.body;
const { proyectoId, anotaciones } = body;

if (!proyectoId) {
  throw new Error('Falta proyectoId');
}

return [{ json: {
  id: proyectoId,
  anotaciones: anotaciones || ''
}}];
